import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"猫耳","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/0.无支线/猫耳.md","filePath":"4.资源分区/7.物品与装备/4.奇物/0.无支线/猫耳.md"}'),p={name:"4.资源分区/7.物品与装备/4.奇物/0.无支线/猫耳.md"};function d(l,a,i,_,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"猫耳",tabindex:"-1"},[s("猫耳 "),e("a",{class:"header-anchor",href:"#猫耳","aria-label":'Permalink to "猫耳"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌037")])])],-1),o('<h1 id="猫耳-1" tabindex="-1">猫耳 <a class="header-anchor" href="#猫耳-1" aria-label="Permalink to &quot;猫耳&quot;">​</a></h1><p>猫耳<br> 250分<br> 占据头部位</p><p>毛茸茸的、灵活的、会动的猫耳，而且真的可以听到声音！提供给那些想要长出猫耳但是又不想真的变成猫娘的轮回者。</p><p>装备后的猫耳会自动长在装备者的头上，自适应地变成装备者头发的颜色，就算头发的颜色是彩虹色也一样。而且耳廓内会有细密的绒毛。你很可能忍不住上手摸一摸。</p><p>同时，现在你有四声道了。装备者获得感知检定上的1点增强加值。</p><p>移除这件装备需要一个标准动作，并且受到1点不可豁免的剧痛点数。</p><p>特别的，在购买时，你也可以指定另一个物种的耳朵，如狗耳、狐耳、熊耳等，这件物品会变成你指定那个物种耳朵的样子，但指定后无法变更。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const m=r(p,[["render",d]]);export{f as __pageData,m as default};
